at::Tensor conv_depthwise_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    // x: [N, C, H, W], weight: [C, 1, KH, KW], stride=1, pad=0, dilation=1, groups=C
    const int64_t N = x.size(0);
    const int64_t C = x.size(1);
    const int64_t H = x.size(2);
    const int64_t W = x.size(3);
    const int64_t KH = weight.size(2);
    const int64_t KW = weight.size(3);
    TORCH_CHECK(KH > 0 && KW > 0, "Invalid kernel size");
    TORCH_CHECK(H >= KH && W >= KW, "Input smaller than kernel with no padding");

    const int64_t outH = H - KH + 1;
    const int64_t outW = W - KW + 1;

    at::Tensor y = at::empty({N, C, outH, outW}, x.options());
    EXEC_NPU_CMD(aclnnConvDepthwise2dSquareInputSquareKernelCustom, x, weight, y);
    return y;
